  /**
   * Source parity: ScriptEngine::enableScript / disableScript.
   * Stores script/group active state keyed by script name.
   */
  setScriptActive(scriptName: string, active: boolean): boolean {
    const normalizedName = scriptName.trim().toUpperCase();
    if (!normalizedName) {
      return false;
    }
    const mapScript = this.mapScriptsByNameUpper.get(normalizedName);
    if (mapScript) {
      mapScript.active = active;
      return true;
    }
    const mapGroup = this.mapScriptGroupsByNameUpper.get(normalizedName);
    if (mapGroup) {
      mapGroup.active = active;
      return true;
    }
    this.scriptActiveByName.set(normalizedName, active);
    return true;
  }

  /**
   * Source parity: Script active-state query used by script action scaffolding.
   */
  isScriptActive(scriptName: string): boolean {
    const normalizedName = scriptName.trim().toUpperCase();
    if (!normalizedName) {
      return false;
    }
    const mapScript = this.mapScriptsByNameUpper.get(normalizedName);
    if (mapScript) {
      return mapScript.active;
    }
    const mapGroup = this.mapScriptGroupsByNameUpper.get(normalizedName);
    if (mapGroup) {
      return mapGroup.active;
    }
    return this.scriptActiveByName.get(normalizedName) ?? true;
  }

  /**
   * Source parity: ScriptEngine::callSubroutine dispatch marker.
   * Group lookup takes precedence over script lookup (matching C++).
   */
  notifyScriptSubroutineCall(scriptName: string): boolean {
    const trimmedName = scriptName.trim();
    const normalizedName = trimmedName.toUpperCase();
    if (!normalizedName) {
      return false;
    }
    this.scriptSubroutineCalls.push(normalizedName);

    const inheritedCallingTeam = this.resolveScriptContextTeamName();
    const inheritedCallingEntity = this.resolveScriptContextEntityId();
    const executeWithInheritedCallingContext = (callback: () => void): void => {
      const previousCallingTeam = this.scriptCallingTeamNameUpper;
      const previousCallingEntity = this.scriptCallingEntityId;
      this.scriptCallingTeamNameUpper = inheritedCallingTeam;
      this.scriptCallingEntityId = inheritedCallingEntity;
      try {
        callback();
      } finally {
        this.scriptCallingTeamNameUpper = previousCallingTeam;
        this.scriptCallingEntityId = previousCallingEntity;
      }
    };

    const mapGroup = this.mapScriptGroupsByNameUpper.get(normalizedName);
    if (mapGroup) {
      if (!mapGroup.subroutine) {
        this.executeScriptDebugMessage('***Attempting to call script that is not a subroutine:***', false, false);
        this.executeScriptDebugMessage(trimmedName, false, false);
        return true;
      }
      if (mapGroup.active) {
        executeWithInheritedCallingContext(() => {
          this.executeMapScriptGroup(mapGroup, false);
        });
      }
      return true;
    }

    const mapScript = this.mapScriptsByNameUpper.get(normalizedName);
    if (mapScript) {
      if (!mapScript.subroutine) {
        this.executeScriptDebugMessage('***Attempting to call script that is not a subroutine:***', false, false);
        this.executeScriptDebugMessage(trimmedName, false, false);
        return true;
      }
      if (mapScript.active) {
        executeWithInheritedCallingContext(() => {
          this.executeMapScript(mapScript, true);
        });
      }
      return true;
    }

    this.executeScriptDebugMessage('***Script not defined:***', false, false);
    this.executeScriptDebugMessage(trimmedName, false, false);
    return true;
  }

  consumeScriptSubroutineCall(scriptName: string): boolean {
    const normalizedName = scriptName.trim().toUpperCase();
    if (!normalizedName) {
      return false;
    }
    const index = this.scriptSubroutineCalls.indexOf(normalizedName);
    if (index === -1) {
      return false;
    }
    this.scriptSubroutineCalls.splice(index, 1);
    return true;
  }

  /**
   * Source parity bridge: ScriptActions::doMoveCameraAlongWaypointPath follows
   * the first outgoing waypoint link chain (Waypoint::getLink(0)).
   */
  resolveScriptCameraWaypointPath(waypointName: string): ReadonlyArray<{ x: number; z: number }> | null {
    const normalizedWaypointName = waypointName.trim().toUpperCase();
    if (!normalizedWaypointName) {
      return null;
    }
    const waypointData = this.loadedMapData?.waypoints;
    if (!waypointData) {
      return null;
    }

    const nodesById = new Map<number, (typeof waypointData.nodes)[number]>();
    for (const node of waypointData.nodes) {
      nodesById.set(node.id, node);
    }

    let currentNode = waypointData.nodes.find(
      (node) => node.name.trim().toUpperCase() === normalizedWaypointName,
    ) ?? null;
    if (!currentNode) {
      return null;
    }

    const maxWaypoints = 25;
    const path: Array<{ x: number; z: number }> = [];
    while (currentNode && path.length < maxWaypoints) {
      path.push({
        x: currentNode.position.x,
        z: currentNode.position.y,
      });
      const nextLink = waypointData.links.find((link) => link.waypoint1 === currentNode!.id);
      if (!nextLink) {
        break;
      }
      currentNode = nodesById.get(nextLink.waypoint2) ?? null;
    }

    return path;
  }

