          // Source parity: HoleHealthRegen%PerSecond uses INI::parsePercentToReal
          // which divides by 100. E.g., INI value "10" → 0.1 (10%). Default = 0.1.
          const regenRaw = readNumericField(block.fields, ['HoleHealthRegen%PerSecond']);
